def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        penalty = 0
        for j in range(5):
            if residual <= 0:
                score += 8
                penalty += (5 - j) * 2
            else:
                score += 1 / (residual + j + 1)
                penalty += j * 0.5
            residual *= 0.6
        if capacity > 3 * item:
            score *= 0.85
            if penalty > 5:
                score -= penalty * 0.1
        elif capacity > 1.5 * item:
            score *= 1.05
            if penalty < 2:
                score += 2
            else:
                score -= penalty * 0.05
        else:
            score *= 1.2
            if penalty > 8:
                score += penalty * 0.2
            else:
                for k in range(3):
                    score += (k + 1) * (item / (capacity + k + 1))
        if np.isinf(priorities[i]):
            continue
        if score > 120:
            priorities[i] = 120
        elif score < 0:
            priorities[i] = 0
        else:
            priorities[i] = score
    for i in range(n):
        if i > 0 and priorities[i] < priorities[i-1]:
            priorities[i] += (priorities[i-1] - priorities[i]) * 0.1
        if i < n-1 and priorities[i] < priorities[i+1]:
            priorities[i] += (priorities[i+1] - priorities[i]) * 0.1
    return priorities
